// Normalize incoming request records to a stable schema
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  out.push({ json: {
    requestId: String(j.requestId ?? j.id ?? '').trim(),
    query: typeof j.query === 'string' ? j.query.trim() : j.query ?? null,
    source: j.source ?? 'api',
    receivedAt: new Date().toISOString(),
  } });
}
return out;

// Build a stable idempotency key per request (djb2 hash, no deps)
function hash(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0;
  return h.toString(16);
}
return $input.all().map(item => {
  const j = item.json;
  return { json: { ...j, idempotencyKey: hash([j.requestId, j.query].join('|')) } };
});
